#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *C = (int*)malloc(N * sizeof(int));
        long long *W = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%d", &C[i]);
        for (int i = 0; i < N; ++i) scanf("%lld", &W[i]);
        int *last = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) last[i] = -1;
        long long curSum = 0, best = 0;
        int left = 0;
        for (int right = 0; right < N; ++right) {
            int val = C[right];
            if (last[val] >= left) {
                // shrink window to exclude previous occurrence
                while (left <= last[val]) {
                    curSum -= W[left];
                    ++left;
                }
            }
            curSum += W[right];
            if (curSum > best) best = curSum;
            last[val] = right;
        }
        printf("%lld\n", best);
        free(C); free(W); free(last);
    }
    return 0;
}

