import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] C = new int[N];
            long[] W = new long[N];
            for (int i = 0; i < N; i++) C[i] = fs.nextInt();
            for (int i = 0; i < N; i++) W[i] = fs.nextLong();
            int[] last = new int[N];
            Arrays.fill(last, -1);
            long cur = 0, best = 0;
            int left = 0;
            for (int right = 0; right < N; right++) {
                int v = C[right];
                if (last[v] >= left) {
                    while (left <= last[v]) {
                        cur -= W[left];
                        left++;
                    }
                }
                cur += W[right];
                if (cur > best) best = cur;
                last[v] = right;
            }
            sb.append(best).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException { int c, sign = 1, val = 0; do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign; }
        long nextLong() throws IOException { int c; long sign = 1, val = 0; do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign; }
    }
}

